{
  "statusCode": 200,
  "success": true,
  "message": "Category retrieved successfully!",
  "data": {
    "id": 1,
    "name": "Electronics",
    "slug": "electronics",
    "products": [
      {
        "product": {
          "id": 10,
          "name": "Laptop",
          "price": 999.99,
          "image": "url...",
          "description": "..."
        }
      }
    ]
  }
}

